Model Training The model is trained using a loss function that combines Dice Loss and Categorical Focal Loss , both of which are well-suited for segmentation tasks. Dice Loss emphasizes the overlap between predictions and ground truth, improving segmentation accuracy, while Focal Loss addresses class imbalance by down-weighting easy examples and focusing on hard-to-classify pixels. Model evaluation is conducted using accuracy , Intersection over Union (IoU) , and a custom Dice Score metric . To enhance convergence, a learning rate scheduler is implemented to reduce the learning rate when validation loss plateaus. The model is optimized using the Nadam optimizer with afixed learning rate of 0.001, and gradient clipping is applied to prevent exploding gradients. For efficient training, data generators are used to load and preprocesstraining and validation data in batches. Additionally, callbacks are incorporated to save the best model and implement early stopping , terminating training if validation loss ceases to improve. def train_and_evaluate(): # Initialize tracking variables epoch_times = [] total_start = time.time() memory_usage = [] cpu_usage = [] # Function to get current memory usage def get_memory_usage(): process = psutil.Process(os.getpid()) return process.memory_info().rss / (1024 ** 2) # Return in MB # Function to get CPU usage def get_cpu_usage(): return psutil.cpu_percent(interval=None) # Data paths DATA_ROOT = &#34;glioma split data&#34; train_img_dir = os.path.join(DATA_ROOT, &#34;train/images/&#34;) train_mask_dir = os.path.join(DATA_ROOT, &#34;train/masks/&#34;) val_img_dir = os.path.join(DATA_ROOT, &#34;val/images/&#34;) val_mask_dir = os.path.join(DATA_ROOT, &#34;val/masks/&#34;) test_img_dir = os.path.join(DATA_ROOT, &#34;test/images/&#34;) test_mask_dir = os.path.join(DATA_ROOT, &#34;test/masks/&#34;) # Get sorted file lists def get_sorted_files(directory): return sorted([f for f in os.listdir(directory) if f.endswith(&#39;.npy&#39;)]) train_img_list = get_sorted_files(train_img_dir) train_mask_list = get_sorted_files(train_mask_dir) val_img_list = get_sorted_files(val_img_dir) val_mask_list = get_sorted_files(val_mask_dir) test_img_list = get_sorted_files(test_img_dir) test_mask_list = get_sorted_files(test_mask_dir) # Training parameters batch_size = 2 patch_size = (96, 96, 96) epochs = 100 # Data generators train_data = imageLoader(train_img_dir, train_img_list, train_mask_dir, train_mask_list, batch_size, patch_size) val_data = imageLoader(val_img_dir, val_img_list, val_mask_dir, val_mask_list, batch_size, patch_size, is_training=False) # Model compilation model = simple_unet_model(IMG_HEIGHT=96, IMG_WIDTH=96, IMG_DEPTH=96, IMG_CHANNELS=4, num_classes=4) # Loss and metrics wt0, wt1, wt2, wt3 = 0.25, 0.25, 0.25, 0.25 class_weights = np.array([wt0, wt1, wt2, wt3], dtype=np.float32) dice_loss = sm.losses.DiceLoss(class_weights=class_weights) focal_loss = sm.losses.CategoricalFocalLoss() total_loss = 0.2 * dice_loss + 0.2 * focal_loss metrics = [&#39;accuracy&#39;, sm.metrics.IOUScore(threshold=0.5), DiceScore(num_classes=4)] optimizer = tf.keras.optimizers.Nadam(learning_rate=0.001, clipnorm=1.0) model.compile(optimizer=optimizer, loss=total_loss, metrics=metrics) # Callbacks checkpoint_path = f&#34;saved_model/3D_unet_{epochs}_epochs_{batch_size}_batch_patch_training.keras&#34; # Custom callback to track epoch times and resource usage class ResourceTracker(keras.callbacks.Callback): def on_epoch_begin(self, epoch, logs=None): self.epoch_start_time = time.time() self.epoch_start_mem = get_memory_usage() self.epoch_start_cpu = get_cpu_usage() def on_epoch_end(self, epoch, logs=None): epoch_time = time.time() - self.epoch_start_time epoch_mem = get_memory_usage() - self.epoch_start_mem epoch_cpu = get_cpu_usage() epoch_times.append(epoch_time) memory_usage.append(epoch_mem) cpu_usage.append(epoch_cpu) logs[&#39;epoch_time&#39;] = epoch_time logs[&#39;memory_usage&#39;] = epoch_mem logs[&#39;cpu_usage&#39;]